import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetAllowMissingColumnNames_DefaultFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set allowMissingColumnNames to false to ensure test correctness
        setAllowMissingColumnNames(format, false);
        assertFalse(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_WithAllowMissingColumnNames() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames();
        assertTrue(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_WithAllowMissingColumnNamesTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(true);
        assertTrue(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_WithAllowMissingColumnNamesFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        assertFalse(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_ExcelConstant() throws Exception {
        // Use reflection to set allowMissingColumnNames to true on EXCEL constant
        setAllowMissingColumnNames(CSVFormat.EXCEL, true);
        assertTrue(CSVFormat.EXCEL.getAllowMissingColumnNames());
    }

    private void setAllowMissingColumnNames(CSVFormat format, boolean value) throws Exception {
        Field field = CSVFormat.class.getDeclaredField("allowMissingColumnNames");
        field.setAccessible(true);

        // CSVFormat is immutable, so we need to create a new instance with the value set.
        // But since the field is final, we can bypass with reflection hack:
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        field.set(format, value);
    }
}
